import argparse
import os
import sys
from datetime import datetime

from dateutil.tz import tzutc, tzlocal, gettz

from . import __version__
from . import ISO_FORMAT, gpstime, GPSTimeParseAction


def check_tz_validity():
    """Check if TZ environment variable is valid.

    Some timezone abbreviations (like 'EDT') are not valid POSIX timezone
    values and will cause the system to fall back to UTC. This function
    detects this condition and warns the user.

    Returns:
        True if TZ is unset or valid, False if TZ is set but invalid.
    """
    tz_env = os.environ.get('TZ')
    if not tz_env:
        return True

    # Use dateutil's gettz to check if TZ is recognized.
    # gettz returns tzlocal() for unrecognized values, and tzfile() for valid ones.
    tz_result = gettz(tz_env)
    if isinstance(tz_result, tzlocal):
        print(f"warning: TZ='{tz_env}' is not a valid timezone specification; "
              f"use IANA names (e.g., 'America/New_York') or POSIX format "
              f"(e.g., 'EST5EDT')",
              file=sys.stderr)
        return False
    return True


PARSER = argparse.ArgumentParser(
    description="""GPS time conversion

Print local, UTC, and GPS time for the specified time string.
""",
    epilog="""See the python datetime module for time formating options:
https://docs.python.org/3/library/datetime.html#strftime-and-strptime-behavior
""",
    formatter_class=argparse.RawDescriptionHelpFormatter)
PARSER.add_argument(
    '-v', '--version', action='version', version=__version__,
    help="show version number and exit")
# parser options
pg = PARSER.add_mutually_exclusive_group()
pg.add_argument(
    '-n', '--nano', action='store_true',
    help="assume time specified as integer GPS nanoseconds")
# output options
zg = PARSER.add_mutually_exclusive_group()
zg.add_argument(
    '-l', '--local', action='store_const', dest='tz', const='local',
    help="print only local time (or timezone specified with 'TZ' env var)")
zg.add_argument(
    '-u', '--utc', action='store_const', dest='tz', const='utc',
    help="print only UTC time")
zg.add_argument(
    '-g', '--gps', action='store_const', dest='tz', const='gps',
    help="print only GPS time")
# format options
fg = PARSER.add_mutually_exclusive_group()
fg.add_argument(
    '-i', '--iso', action='store_const', dest='format', const=ISO_FORMAT,
    help="use ISO time format")
fg.add_argument(
    '-f', '--format',
    help="specify time format (see below), or printf numeric format for GPS times")
PARSER.add_argument(
    'time', metavar='TIME', action=GPSTimeParseAction, nargs='*', default='now',
    help="time string in any format (including GPS), or current time if not specified")


def tzname(tz):
    return gpstime.now(tz).tzname()


def main():
    args = PARSER.parse_args()

    tz_valid = check_tz_validity()

    if args.tz == 'local' and not tz_valid:
        sys.exit("error: -l/--local requires a valid TZ environment variable")

    if args.tz == 'gps' and args.format == ISO_FORMAT:
        PARSER.error("argument -g/--gps: not allowed with argument -i/--iso")

    if not args.format:
        if args.tz == 'gps':
            args.format = '%.6f'
        else:
            args.format = '%Y-%m-%d %H:%M:%S.%f %Z'

    gt = args.time

    gps = gt.gps()

    if not args.tz:
        ltz = tzlocal()
        utz = tzutc()
        if tz_valid:
            print('{}: {}'.format(tzname(ltz), gt.astimezone(ltz).strftime(args.format)))
        print('{}: {}'.format('UTC', gt.astimezone(utz).strftime(args.format)))
        print('{}: {:.6f}'.format('GPS', gps))
    elif args.tz == 'gps':
        print(args.format % gps)
    else:
        if args.tz == 'local':
            tz = tzlocal()
            if args.format == ISO_FORMAT:
                args.format = args.format[:-1]
        elif args.tz == 'utc':
            tz = tzutc()
        print('{}'.format(gt.astimezone(tz).strftime(args.format)))

##################################################

if __name__ == '__main__':
    main()
